    }
}
```

**2. 旋钮控制**
```java
// 旋钮事件监听
public class RotaryController {
    private int mFocusIndex = 0;

    public boolean onRotate(int direction) {
        if (direction == ROTARY_CW) {
            mFocusIndex = (mFocusIndex + 1) % mButtons.size();
        } else {
            mFocusIndex = (mFocusIndex - 1 + mButtons.size()) % mButtons.size();
        }
        mButtons.get(mFocusIndex).requestFocus();
        return true;
    }

    public boolean onCenterClick() {
        mButtons.get(mFocusIndex).performClick();
        return true;
    }
}
```

**3. 方向盘按键**
```java
// 监听方向盘事件
